export const getGetAuditLogsUrl = (params?: GetAuditLogsParams,) => {
  const normalizedParams = new URLSearchParams();

  Object.entries(params || {}).forEach(([key, value]) => {

    if (value !== undefined) {
      normalizedParams.append(key, value === null ? 'null' : String(value))
    }
  });

  const stringifiedParams = normalizedParams.toString();

  return stringifiedParams.length > 0 ? `/api/audit?${stringifiedParams}` : `/api/audit`
}

/**
 * @summary Get audit logs
 */
export const getAuditLogs = async (params?: GetAuditLogsParams, options?: RequestInit): Promise<AuditLog[]> => {

  return customFetch<AuditLog[]>(getGetAuditLogsUrl(params),
  {
    ...options,
    method: 'GET'


  }
);}





